@rendermode InteractiveServer

<div class="star-rating">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= _selectedRating ? "filled" : "")"
                  @onclick="() => Rate(star)"
                  role="button"
                  title="Rate @star star(s)">
                @(star <= _selectedRating ? "★" : "☆")
            </span>
        }
    </div>
    @if (_submitted)
    {
        <span class="text-success ms-2">Thanks for rating!</span>
    }
    <div class="text-muted small mt-1">
        Average: @AverageRating.ToString("0.0") / 5 (@RatingCount ratings)
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int _selectedRating;
    private bool _submitted;

    private void Rate(int stars)
    {
        if (_submitted) return;
        _selectedRating = stars;
        _submitted = true;
        RecipeStore.AddRating(RecipeId, stars);
        var recipe = RecipeStore.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

.star-rating {
    margin: 1rem 0;
}

.stars {
    font-size: 1.5rem;
}

.star {
    cursor: pointer;
    color: #ccc;
    transition: color 0.2s;
}

.star.filled {
    color: #f5a623;
}

.star:hover {
    color: #f5a623;
}

