@page "/category/{CategoryName}"

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@CategoryName Recipes</h1>

    @if (!_recipes.Any())
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
    else
    {
        <div class="row g-4 mt-3">
            @foreach (var recipe in _recipes)
            {
                <div class="col-md-6">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h4 class="card-title">@recipe.Title</h4>
                            <p class="card-text text-muted">
                                @(recipe.RatingCount > 0
                                    ? $"★ {recipe.AverageRating:0.0} ({recipe.RatingCount} ratings)"
                                    : "No ratings yet")
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IEnumerable<Recipe> _recipes = Enumerable.Empty<Recipe>();

    protected override void OnParametersSet()
    {
        _recipes = RecipeStore.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(_recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (_recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
                <li class="breadcrumb-item active">@_recipe.Title</li>
            }
        </ol>
    </nav>

    @if (_recipe is null)
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
    else
    {
        <h1>@_recipe.Title</h1>
        <span class="badge bg-secondary mb-3">@_recipe.Category</span>

        <RecipeShare.Components.Shared.StarRating
            RecipeId="@_recipe.Id"
            AverageRating="@_recipe.AverageRating"
            RatingCount="@_recipe.RatingCount" />

        <div class="row mt-4">
            <div class="col-md-5">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                    <div class="card-body">
                        <ul class="list-unstyled mb-0">
                            @foreach (var ingredient in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                            {
                                <li class="mb-1">• @ingredient</li>
                            }
                        </ul>
                    </div>
